public class Strings {
    public static String repeat(String s, int times) {
        if (times <= 0) {
            return "";
        }
        StringBuilder sb = new StringBuilder(s.length() * times);
        for (int i = 0; i < times; i++) {
            sb.append(s);
        }
        return sb.toString();
    }
}

public class StringUtils {
    public static boolean isBlank(String s) {
        if (s == null) {
            return true;
        }
        for (int i = 0; i < s.length(); i++) {
            if (!Character.isWhitespace(s.charAt(i))) {
                return false;
            }
        }
        return true;
    }
}

public class Pricing {
    public double computeTotal(List<Item> items, double taxRate, double discountThreshold) {
        double subtotal = 0.0;
        int count = 0;
        for (Item item : items) {
            subtotal += item.getPrice() * item.getQuantity();
            count += item.getQuantity();
        }
        double discount = 0.0;
        if (subtotal >= discountThreshold) {
            discount = subtotal * 0.05;
        }
        if (count >= 10) {
            discount += subtotal * 0.02;
        }
        double afterDiscount = subtotal - discount;
        double tax = afterDiscount * taxRate;
        double total = afterDiscount + tax;
        return Math.round(total * 100.0) / 100.0;
    }
}

public class HttpClientFactory {
    public HttpClient build(ClientConfig config) {
        HttpClient.Builder builder = HttpClient.newBuilder();
        if (config.getTimeout() != null) {
            builder.connectTimeout(Duration.ofMillis(config.getTimeout()));
        }
        if (config.getProxy() != null) {
            ProxySelector proxy = ProxySelector.of(
                new InetSocketAddress(config.getProxy().getHost(), config.getProxy().getPort())
            );
            builder.proxy(proxy);
        }
        if (config.getFollowRedirects()) {
            builder.followRedirects(HttpClient.Redirect.ALWAYS);
        } else {
            builder.followRedirects(HttpClient.Redirect.NEVER);
        }
        if (config.getAuthenticator() != null) {
            builder.authenticator(config.getAuthenticator());
        }
        if (config.getVersion() == HttpVersion.HTTP_2) {
            builder.version(HttpClient.Version.HTTP_2);
        } else {
            builder.version(HttpClient.Version.HTTP_1_1);
        }
        return builder.build();
    }
}

public class Geometry {
    public double area(double a, double b, double c, double d, double e, double f) {
        double x1 = a * b;
        double x2 = c * d;
        double x3 = e * f;
        double y1 = a + c;
        double y2 = b + d;
        double y3 = e + a;
        double z1 = x1 + y1;
        double z2 = x2 + y2;
        double z3 = x3 + y3;
        double w1 = z1 * z2;
        double w2 = z2 * z3;
        double w3 = z3 * z1;
        double u = w1 + w2 + w3;
        double v = w1 * w2 * w3;
        double p = u + v;
        double q = u - v;
        double r = p * q;
        return Math.abs(r) / 2.0;
    }
}

public class Validator {
    public List<String> validate(Map<String, Object> data, Map<String, Rule> schema) {
        List<String> errors = new ArrayList<>();
        for (Map.Entry<String, Rule> entry : schema.entrySet()) {
            String key = entry.getKey();
            Rule rule = entry.getValue();
            if (!data.containsKey(key)) {
                if (rule.isRequired()) {
                    errors.add(key + " is required");
                }
                continue;
            }
            Object value = data.get(key);
            if (rule.getType() != null) {
                if (!rule.getType().isInstance(value)) {
                    errors.add(key + " has wrong type");
                    continue;
                }
            }
            if (rule.getMin() != null) {
                if (value instanceof Number) {
                    if (((Number) value).doubleValue() < rule.getMin()) {
                        errors.add(key + " below min");
                    }
                } else if (value instanceof String) {
                    if (((String) value).length() < rule.getMin()) {
                        errors.add(key + " too short");
                    }
                } else if (value instanceof List) {
                    if (((List<?>) value).size() < rule.getMin()) {
                        errors.add(key + " too few items");
                    }
                }
            }
            if (rule.getChoices() != null && !rule.getChoices().contains(value)) {
                errors.add(key + " not in choices");
            }
        }
        return errors;
    }
}

public class ExpressionParser {
    private List<Token> tokens;
    private int pos;

    public Node parseExpression() {
        Node left = parseTerm();
        while (pos < tokens.size()) {
            Token tok = tokens.get(pos);
            if (tok.type == TokenType.PLUS || tok.type == TokenType.MINUS) {
                pos++;
                Node right = parseTerm();
                left = new BinaryOp(tok.type, left, right);
            } else {
                break;
            }
        }
        return left;
    }

    private Node parseTerm() {
        Node left = parseFactor();
        while (pos < tokens.size()) {
            Token tok = tokens.get(pos);
            if (tok.type == TokenType.STAR || tok.type == TokenType.SLASH) {
                pos++;
                Node right = parseFactor();
                left = new BinaryOp(tok.type, left, right);
            } else {
                break;
            }
        }
        return left;
    }

    private Node parseFactor() {
        Token tok = tokens.get(pos);
        if (tok.type == TokenType.NUMBER) {
            pos++;
            return new Literal(tok.value);
        } else if (tok.type == TokenType.LPAREN) {
            pos++;
            Node expr = parseExpression();
            if (pos >= tokens.size() || tokens.get(pos).type != TokenType.RPAREN) {
                throw new ParseException("Expected )");
            }
            pos++;
            return expr;
        } else if (tok.type == TokenType.MINUS) {
            pos++;
            Node operand = parseFactor();
            return new UnaryOp(tok.type, operand);
        } else if (tok.type == TokenType.IDENT) {
            pos++;
            return new Variable(tok.value);
        }
        throw new ParseException("Unexpected token: " + tok);
    }
}

public class F {
    public int f(int a, int b, int[] c, int[] d, int[] e, int[][] g) {
        int r = 0;
        int s = 0;
        int t = 0;
        if (a > 0) {
            for (int i = 0; i < b; i++) {
                if (c[i] != 0) {
                    for (int j = 0; j < d.length; j++) {
                        if (e[j] != 0) {
                            if (g[i][j] != 0) {
                                if (c[i] > e[0]) {
                                    r += a * (c[i] - d[j]) / (e[j] + 1);
                                } else {
                                    s -= a * b + c[i] * d[j] - e[j];
                                }
                            } else if (g[i][j] < 0) {
                                t += a + b + c[i] + d[j] + e[j];
                            } else {
                                if (i % 2 == 0) {
                                    r += b * d[j];
                                } else {
                                    s += b * d[j];
                                }
                            }
                        } else if (d.length > 0) {
                            if (c[i] > e[0]) {
                                r += a * d[j];
                            }
                        }
                    }
                } else if (b > c[0]) {
                    t += a + b + c[0];
                }
            }
            for (int k = 0; k < b; k++) {
                if (c[k] != 0 && e[k] != 0) {
                    r += g[k][0] * 2;
                    s -= g[k][0];
                }
            }
        }
        return r + s + t;
    }
}

public class OrderProcessor {
    public ProcessResult process(Order order, Inventory inv, PricingRules rules, Customer cust, Map<String, Discount> promos) {
        ProcessResult result = new ProcessResult();
        for (LineItem item : order.getItems()) {
            if (inv.has(item.getSku())) {
                int available = inv.getStock(item.getSku());
                if (available >= item.getQuantity()) {
                    double price = rules.basePrice(item.getSku());
                    if (cust.getTier() == Tier.GOLD) {
                        if (rules.allowsTierDiscount(item.getSku())) {
                            price *= 0.85;
                        } else if (cust.getYearsActive() > 5) {
                            price *= 0.92;
                        }
                    } else if (cust.getTier() == Tier.SILVER) {
                        if (rules.allowsTierDiscount(item.getSku())) {
                            price *= 0.92;
                        }
                    }
                    for (String code : item.getPromoCodes()) {
                        if (promos.containsKey(code)) {
                            Discount d = promos.get(code);
                            if (d.getMinQuantity() <= item.getQuantity()) {
                                if (d.getType() == DiscountType.PERCENT) {
                                    price *= (1.0 - d.getValue() / 100.0);
                                } else if (d.getType() == DiscountType.FIXED) {
                                    price = Math.max(0, price - d.getValue());
                                }
                                if (d.isExclusive()) {
                                    break;
                                }
                            }
                        }
                    }
                    result.addLine(item.getSku(), item.getQuantity(), price);
                    inv.decrement(item.getSku(), item.getQuantity());
                } else {
                    if (inv.allowBackorder(item.getSku())) {
                        result.addBackorder(item.getSku(), item.getQuantity() - available);
                        result.addLine(item.getSku(), available, rules.basePrice(item.getSku()));
                    } else {
                        result.addFailed(item.getSku(), "insufficient stock");
                    }
                }
            } else {
                result.addFailed(item.getSku(), "not in inventory");
            }
        }
        return result;
    }
}

public class StatusFormatter {
    public enum Status { ACTIVE, INACTIVE, PENDING, SUSPENDED, ARCHIVED }

    public String format(Status status, boolean verbose) {
        return switch (status) {
            case ACTIVE -> verbose ? "Account is active" : "active";
            case INACTIVE -> verbose ? "Account is inactive" : "inactive";
            case PENDING -> verbose ? "Awaiting approval" : "pending";
            case SUSPENDED -> verbose ? "Temporarily suspended" : "suspended";
            case ARCHIVED -> verbose ? "Archived (read-only)" : "archived";
        };
    }
}

import java.util.*;
import java.util.stream.Collectors;
import java.util.stream.Stream;

public class OrderAnalyzer {
    public Map<String, Double> revenuePerCategoryAboveThreshold(
        List<Order> orders, double threshold, String region
    ) {
        return orders.stream()
            .filter(o -> o.getRegion().equals(region))
            .filter(o -> o.getStatus() == OrderStatus.COMPLETED)
            .flatMap(o -> o.getLineItems().stream())
            .collect(Collectors.groupingBy(
                LineItem::getCategory,
                Collectors.summingDouble(li -> li.getUnitPrice() * li.getQuantity())
            ))
            .entrySet().stream()
            .filter(e -> e.getValue() >= threshold)
            .sorted(Map.Entry.<String, Double>comparingByValue().reversed())
            .collect(Collectors.toMap(
                Map.Entry::getKey,
                Map.Entry::getValue,
                (a, b) -> a,
                LinkedHashMap::new
            ));
    }
}

import java.util.List;
import java.util.ArrayList;

public class CsvLineParser {
    /**
     * Parse une ligne CSV en respectant les guillemets et virgules échappées.
     */
    public List<String> parseLine(String line, char delimiter) {
        // Étape 1 : initialisation
        List<String> fields = new ArrayList<>();
        StringBuilder current = new StringBuilder();
        boolean inQuotes = false;

        // Étape 2 : parcours caractère par caractère
        for (int i = 0; i < line.length(); i++) {
            char c = line.charAt(i);
            boolean atDelimiter = c == delimiter && !inQuotes;
            boolean atQuote = c == '"';

            if (atDelimiter) {
                fields.add(current.toString());
                current.setLength(0);
            } else if (atQuote) {
                inQuotes = !inQuotes;
            } else {
                current.append(c);
            }
        }

        // Étape 3 : ajouter le dernier champ
        fields.add(current.toString());
        return fields;
    }
}

