public class TransactionService {
    public boolean transferFunds(Connection conn, long fromId, long toId,
                                    double amount, String currency, String reason) {
        if (amount <= 0) throw new IllegalArgumentException("amount must be positive");
        boolean autoCommitOriginal = false;
        Savepoint savepoint = null;
        try {
            autoCommitOriginal = conn.getAutoCommit();
            conn.setAutoCommit(false);
            savepoint = conn.setSavepoint("transfer");

            try (PreparedStatement debit = conn.prepareStatement(
                "UPDATE accounts SET balance = balance - ? WHERE id = ? AND currency = ?"
            )) {
                debit.setDouble(1, amount);
                debit.setLong(2, fromId);
                debit.setString(3, currency);
                int rows = debit.executeUpdate();
                if (rows == 0) {
                    conn.rollback(savepoint);
                    return false;
                }
            }
            try (PreparedStatement credit = conn.prepareStatement(
                "UPDATE accounts SET balance = balance + ? WHERE id = ? AND currency = ?"
            )) {
                credit.setDouble(1, amount);
                credit.setLong(2, toId);
                credit.setString(3, currency);
                int rows = credit.executeUpdate();
                if (rows == 0) {
                    conn.rollback(savepoint);
                    return false;
                }
            }
            try (PreparedStatement log = conn.prepareStatement(
                "INSERT INTO ledger (from_id, to_id, amount, currency, reason) VALUES (?, ?, ?, ?, ?)"
            )) {
                log.setLong(1, fromId);
                log.setLong(2, toId);
                log.setDouble(3, amount);
                log.setString(4, currency);
                log.setString(5, reason);
                log.executeUpdate();
            }
            conn.commit();
            return true;
        } catch (SQLException e) {
            try {
                if (savepoint != null) conn.rollback(savepoint);
                else conn.rollback();
            } catch (SQLException ignored) {}
            throw new RuntimeException("transfer failed", e);
        } finally {
            try { conn.setAutoCommit(autoCommitOriginal); } catch (SQLException ignored) {}
        }
    }
}

public class HttpRequestBuilder {
    private String method = "GET";
    private String url;
    private final Map<String, String> headers = new HashMap<>();
    private byte[] body;
    private int timeoutMs = 30_000;

    public HttpRequestBuilder method(String method) {
        this.method = method.toUpperCase();
        return this;
    }

    public HttpRequestBuilder url(String url) {
        this.url = url;
        return this;
    }

    public HttpRequestBuilder header(String name, String value) {
        this.headers.put(name, value);
        return this;
    }

    public HttpRequestBuilder body(byte[] body) {
        this.body = body;
        return this;
    }

    public HttpRequestBuilder timeout(int milliseconds) {
        if (milliseconds <= 0) {
            throw new IllegalArgumentException("timeout must be positive");
        }
        this.timeoutMs = milliseconds;
        return this;
    }

    public HttpRequest build() {
        if (url == null) {
            throw new IllegalStateException("url is required");
        }
        if ((method.equals("POST") || method.equals("PUT")) && body == null) {
            throw new IllegalStateException(method + " requires body");
        }
        return new HttpRequest(method, url, headers, body, timeoutMs);
    }
}
